export const dynamic = "force-static";

const HTML = "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"UTF-8\" />\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\n<title>Endurance Brain — Institutional memory, finally autonomous.</title>\n<meta name=\"description\" content=\"Endurance Brain turns everything your firm produces — email, chat, documents, meetings, deals, code — into a living, self-maintaining knowledge base that answers with citations and never hallucinates. By Endurance AI Labs.\" />\n<link rel=\"preconnect\" href=\"https://fonts.googleapis.com\">\n<link rel=\"preconnect\" href=\"https://fonts.gstatic.com\" crossorigin>\n<link href=\"https://fonts.googleapis.com/css2?family=Instrument+Serif:ital@0;1&family=Lato:wght@300;400;700;900&family=Space+Mono:wght@400;700&display=swap\" rel=\"stylesheet\">\n<style>\n  :root{\n    --bg:#fafaf8;\n    --bg-2:#f2f2ef;\n    --bg-3:#f7f7f5;\n    --ink:#1a1a18;\n    --muted:#71716b;\n    --muted-2:#a6a69f;\n    --line:#e7e6e1;\n    --line-2:#d6d5cf;\n    --gold:#2e6ff2;\n    --gold-soft:#4a80f5;\n    --gold-dim:rgba(46,111,242,.12);\n    --flare:#1d55d4;\n    --serif:'Instrument Serif',Georgia,'Times New Roman',serif;\n    --sans:'Lato',system-ui,-apple-system,sans-serif;\n    --mono:'Space Mono',ui-monospace,SFMono-Regular,Menlo,monospace;\n    --maxw:1180px;\n    --r:14px;\n  }\n  *{box-sizing:border-box;margin:0;padding:0}\n  html{scroll-behavior:smooth}\n  body{\n    background:var(--bg);\n    color:var(--ink);\n    font-family:var(--sans);\n    font-weight:400;\n    line-height:1.6;\n    -webkit-font-smoothing:antialiased;\n    overflow-x:hidden;\n  }\n  a{color:inherit;text-decoration:none}\n  .wrap{max-width:var(--maxw);margin:0 auto;padding:0 28px}\n  .eyebrow{\n    font-size:10.5px;font-weight:700;letter-spacing:.24em;text-transform:uppercase;\n    color:var(--muted);font-family:var(--mono);\n  }\n  .eyebrow .dot{color:var(--gold)}\n  h1,h2{font-family:var(--serif);font-weight:400;letter-spacing:-.01em;line-height:1.02}\n  h3{font-family:var(--sans);letter-spacing:-.01em;line-height:1.12;font-weight:700}\n  .serif{font-family:var(--serif);font-weight:400}\n  .gold{color:var(--gold)}\n  .mono{font-family:var(--mono)}\n\n  /* ---------- NAV ---------- */\n  header.nav{\n    position:fixed;top:0;left:0;right:0;z-index:100;\n    backdrop-filter:blur(14px);\n    background:rgba(250,250,248,.72);\n    border-bottom:1px solid transparent;\n    transition:border-color .3s, background .3s;\n  }\n  header.nav.scrolled{border-bottom:1px solid var(--line);background:rgba(250,250,248,.9)}\n  .nav-in{display:flex;align-items:center;justify-content:space-between;height:68px;max-width:var(--maxw);margin:0 auto;padding:0 28px}\n  .brand{display:flex;align-items:center;gap:13px;font-weight:700;letter-spacing:-.01em;font-size:16px}\n  .brand .wordmark{height:20px;width:auto;display:block}\n  .brand .bdiv{width:1px;height:19px;background:var(--line-2);display:block}\n  .brand .bprod{color:var(--gold);font-weight:700;font-size:17px;letter-spacing:-.01em}\n  footer .brand .wordmark{height:24px}\n  .nav-links{display:flex;gap:30px;align-items:center}\n  .nav-links a{font-size:14px;color:var(--muted);transition:color .2s;font-weight:500}\n  .nav-links a:hover{color:var(--ink)}\n  .nav-links a.nav-reel{color:var(--gold);font-weight:700}\n  .nav-links a.nav-reel:hover{color:var(--gold-soft)}\n  .btn{\n    display:inline-flex;align-items:center;gap:8px;font-size:14px;font-weight:600;\n    padding:10px 20px;border-radius:999px;transition:.2s;cursor:pointer;border:1px solid transparent;white-space:nowrap;\n  }\n  .btn-gold{background:var(--gold);color:#ffffff;box-shadow:0 0 0 rgba(46,111,242,0)}\n  .btn-gold:hover{background:var(--gold-soft);box-shadow:0 8px 30px rgba(46,111,242,.28);transform:translateY(-1px)}\n  .btn-ghost{border-color:var(--line-2);color:var(--ink)}\n  .btn-ghost:hover{border-color:var(--gold);color:var(--gold)}\n  .nav-cta{display:flex;gap:12px;align-items:center}\n  .nav-toggle{display:none;background:none;border:0;color:var(--ink);cursor:pointer}\n\n  /* ---------- HERO ---------- */\n  .hero{position:relative;min-height:100vh;display:flex;align-items:center;overflow:hidden;padding-top:68px}\n  #net{position:absolute;inset:0;width:100%;height:100%;z-index:0;opacity:1}\n  .hero-glow{\n    position:absolute;z-index:0;width:900px;height:900px;border-radius:50%;\n    right:-280px;top:-120px;\n    background:\n      radial-gradient(circle at 62% 42%, rgba(29,85,212,.12), transparent 52%),\n      radial-gradient(circle, rgba(46,111,242,.16), rgba(46,111,242,0) 62%);\n    filter:blur(20px);pointer-events:none;\n  }\n  .hero-fade{position:absolute;inset:0;z-index:1;pointer-events:none;\n    background:\n      linear-gradient(to bottom, transparent 72%, var(--bg) 100%),\n      linear-gradient(100deg, rgba(250,250,248,.92) 0%, rgba(250,250,248,.5) 42%, rgba(250,250,248,.12) 72%, rgba(250,250,248,.42) 100%);}\n  .hero-in{position:relative;z-index:2;width:100%}\n  .hero-grid{display:grid;grid-template-columns:1fr;gap:0;max-width:760px}\n  .hero .tag{display:inline-flex;align-items:center;gap:10px;border:1px solid var(--line);background:rgba(20,20,18,.02);padding:7px 14px;border-radius:999px;margin-bottom:30px}\n  .hero .tag .pip{width:7px;height:7px;border-radius:50%;background:var(--gold);box-shadow:0 0 10px var(--gold)}\n  .hero .tag span{font-size:12px;color:var(--muted);letter-spacing:.04em}\n  .hero h1{font-size:clamp(46px,8vw,96px);font-weight:400;margin-bottom:26px;line-height:.98}\n  .hero h1 .l2{color:var(--gold);font-style:italic}\n  .hero p.sub{font-size:clamp(16px,2vw,20px);color:var(--muted);max-width:560px;margin-bottom:38px;line-height:1.55;font-weight:400}\n  .hero p.sub strong{color:var(--ink);font-weight:500}\n  .hero-cta{display:flex;gap:14px;flex-wrap:wrap;align-items:center}\n  .hero-meta{display:flex;gap:34px;margin-top:54px;flex-wrap:wrap}\n  .hero-meta .m b{display:block;font-size:36px;font-weight:400;letter-spacing:-.01em;font-family:var(--serif);color:var(--gold)}\n  .hero-meta .m span{font-size:12px;color:var(--muted);letter-spacing:.05em}\n  .scroll-hint{position:absolute;bottom:26px;left:50%;transform:translateX(-50%);z-index:2;font-size:11px;letter-spacing:.3em;color:var(--muted-2);text-transform:uppercase;font-family:var(--mono)}\n  .coords{font-family:var(--mono);font-size:9.5px;font-weight:400;letter-spacing:.22em;text-transform:uppercase;color:rgba(26,26,24,.5)}\n  .coords .dot{color:var(--flare)}\n\n  /* ---------- MARQUEE / TRUST ---------- */\n  .trust{border-top:1px solid var(--line);border-bottom:1px solid var(--line);background:var(--bg-2);padding:54px 0}\n  .trust .lbl{text-align:center;font-size:11px;letter-spacing:.28em;text-transform:uppercase;color:var(--muted-2);margin-bottom:8px;font-family:var(--mono)}\n  .trust .lbl b{color:var(--ink);font-weight:700}\n  .trust .lsub{text-align:center;color:var(--muted);font-size:15px;max-width:560px;margin:0 auto 40px}\n  .src-groups{display:grid;grid-template-columns:repeat(4,1fr);gap:34px 26px}\n  .src-cat h5{font-size:10.5px;letter-spacing:.18em;text-transform:uppercase;color:var(--gold);font-family:var(--mono);margin-bottom:14px;display:flex;align-items:center;gap:8px}\n  .src-cat h5::before{content:\"\";width:5px;height:5px;border-radius:50%;background:var(--gold);box-shadow:0 0 8px var(--gold)}\n  .src-cat .chips{display:flex;flex-wrap:wrap;gap:8px}\n  .src-cat .chips span{font-size:12.5px;color:var(--muted);border:1px solid var(--line);border-radius:999px;padding:5px 12px;transition:.2s;white-space:nowrap}\n  .src-cat .chips span:hover{border-color:var(--gold);color:var(--ink)}\n  .src-foot{text-align:center;margin-top:38px;font-size:14px;color:var(--muted)}\n\n  /* ---------- SECTION SHELL ---------- */\n  section{position:relative;padding:110px 0}\n  .sec-head{max-width:680px;margin-bottom:60px}\n  .sec-head.center{margin-left:auto;margin-right:auto;text-align:center}\n  .sec-head h2{font-size:clamp(30px,4.4vw,50px);margin:18px 0 20px}\n  .sec-head p{font-size:18px;color:var(--muted);line-height:1.55}\n\n  /* ---------- PROBLEM ---------- */\n  .problem{background:linear-gradient(180deg,var(--bg),#f2f2ef)}\n  .prob-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:22px}\n  .prob-card{border:1px solid var(--line);border-radius:var(--r);padding:30px;background:var(--bg-2);transition:.25s}\n  .prob-card:hover{border-color:var(--line-2);transform:translateY(-3px)}\n  .prob-card .n{font-family:var(--mono);color:var(--gold);font-size:13px;margin-bottom:18px;letter-spacing:.1em}\n  .prob-card h3{font-size:20px;margin-bottom:10px;font-weight:700}\n  .prob-card p{font-size:15px;color:var(--muted);line-height:1.55}\n\n  /* ---------- HOW (3 layers) ---------- */\n  .how{background:var(--bg)}\n  .layers{display:grid;grid-template-columns:1fr;gap:18px;max-width:980px;margin:0 auto}\n  .layer{\n    display:grid;grid-template-columns:120px 1fr;gap:30px;align-items:center;\n    border:1px solid var(--line);border-radius:var(--r);padding:34px 34px;background:var(--bg-2);position:relative;overflow:hidden;transition:.25s;\n  }\n  .layer:hover{border-color:var(--line-2)}\n  .layer .lnum{font-family:var(--mono);font-size:13px;color:var(--gold);letter-spacing:.1em}\n  .layer .lnum b{display:block;font-size:52px;color:var(--ink);font-weight:400;letter-spacing:-.01em;margin-top:6px;line-height:1;font-family:var(--serif)}\n  .layer h3{font-size:23px;margin-bottom:10px;font-weight:700}\n  .layer p{color:var(--muted);font-size:15.5px;max-width:560px}\n  .layer .lpill{display:inline-block;font-size:11px;font-family:var(--mono);color:var(--gold);border:1px solid var(--gold-dim);background:var(--gold-dim);padding:4px 10px;border-radius:6px;margin-top:14px;letter-spacing:.05em}\n  .flowline{height:26px;width:1px;background:linear-gradient(var(--gold),transparent);margin:0 auto;opacity:.5}\n\n  /* ---------- FEATURES ---------- */\n  .features{background:linear-gradient(180deg,#f2f2ef,var(--bg))}\n  .feat-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:20px}\n  .feat{border:1px solid var(--line);border-radius:var(--r);padding:28px;background:var(--bg-2);transition:.25s;position:relative}\n  .feat:hover{border-color:var(--gold);transform:translateY(-3px);box-shadow:0 18px 50px -30px rgba(46,111,242,.5)}\n  .feat .ic{width:44px;height:44px;border-radius:11px;display:grid;place-items:center;background:var(--gold-dim);border:1px solid var(--gold-dim);margin-bottom:20px}\n  .feat .ic svg{width:22px;height:22px;stroke:var(--gold)}\n  .feat h3{font-size:18px;margin-bottom:9px;font-weight:700}\n  .feat p{font-size:14.5px;color:var(--muted);line-height:1.55}\n\n  /* ---------- CITATION SHOWCASE ---------- */\n  .showcase{background:var(--bg)}\n  .show-grid{display:grid;grid-template-columns:1fr 1fr;gap:56px;align-items:center}\n  .show-copy h2{font-size:clamp(28px,4vw,44px);margin:18px 0 22px}\n  .show-copy p{color:var(--muted);font-size:17px;margin-bottom:18px;line-height:1.6}\n  .show-list{list-style:none;margin-top:26px;display:grid;gap:14px}\n  .show-list li{display:flex;gap:13px;align-items:flex-start;font-size:15px;color:var(--ink)}\n  .show-list li svg{flex:0 0 auto;width:20px;height:20px;stroke:var(--gold);margin-top:2px}\n  .show-list li span{color:var(--muted)}\n  .terminal{border:1px solid var(--line-2);border-radius:14px;background:linear-gradient(180deg,#ffffff,#f7f7f5);overflow:hidden;box-shadow:0 30px 80px -40px rgba(0,0,0,.9)}\n  .term-bar{display:flex;align-items:center;gap:7px;padding:13px 16px;border-bottom:1px solid var(--line);background:rgba(20,20,18,.02)}\n  .term-bar i{width:11px;height:11px;border-radius:50%;display:block;background:#2a2a2a}\n  .term-bar i:nth-child(1){background:#ff5f56}.term-bar i:nth-child(2){background:#ffbd2e}.term-bar i:nth-child(3){background:#27c93f}\n  .term-bar span{margin-left:10px;font-family:var(--mono);font-size:12px;color:var(--muted-2)}\n  .term-body{padding:22px;font-family:var(--mono);font-size:13px;line-height:1.85}\n  .term-body .q{color:var(--gold)}\n  .term-body .a{color:var(--ink)}\n  .term-body .cite{color:#6ea8fe}\n  .term-body .dim{color:var(--muted-2)}\n  .term-body .ok{color:#27c93f}\n\n  /* ---------- INDUSTRIES ---------- */\n  .industries{background:linear-gradient(180deg,var(--bg),#f2f2ef)}\n  .ind-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:20px}\n  .ind{border:1px solid var(--line);border-radius:var(--r);padding:30px;background:var(--bg-2);transition:.28s;position:relative;overflow:hidden}\n  .ind::before{content:\"\";position:absolute;inset:0;background:radial-gradient(circle at 100% 0,var(--gold-dim),transparent 55%);opacity:0;transition:.3s}\n  .ind:hover{border-color:var(--line-2);transform:translateY(-4px)}\n  .ind:hover::before{opacity:1}\n  .ind .ihead{display:flex;align-items:center;gap:13px;margin-bottom:16px;position:relative}\n  .ind .iic{width:42px;height:42px;border-radius:10px;display:grid;place-items:center;background:rgba(20,20,18,.03);border:1px solid var(--line);flex:0 0 auto}\n  .ind .iic svg{width:21px;height:21px;stroke:var(--gold)}\n  .ind h3{font-size:18px;font-weight:700;position:relative}\n  .ind p{font-size:14px;color:var(--muted);line-height:1.55;position:relative;margin-bottom:14px}\n  .ind ul{list-style:none;position:relative;display:grid;gap:7px}\n  .ind ul li{font-size:13px;color:var(--muted);display:flex;gap:8px;align-items:flex-start}\n  .ind ul li::before{content:\"→\";color:var(--gold);flex:0 0 auto}\n\n  /* ---------- DIFFERENTIATOR / vs RAG ---------- */\n  .versus{background:var(--bg)}\n  .cmp{display:grid;grid-template-columns:1fr 1fr;gap:0;border:1px solid var(--line);border-radius:var(--r);overflow:hidden;max-width:960px;margin:0 auto}\n  .cmp .col{padding:38px}\n  .cmp .col.them{background:var(--bg-2);border-right:1px solid var(--line)}\n  .cmp .col.us{background:linear-gradient(180deg,rgba(46,111,242,.05),transparent)}\n  .cmp h3{font-size:15px;letter-spacing:.04em;margin-bottom:24px;font-weight:700;display:flex;align-items:center;gap:10px}\n  .cmp .col.them h3{color:var(--muted)}\n  .cmp .col.us h3{color:var(--gold)}\n  .cmp ul{list-style:none;display:grid;gap:16px}\n  .cmp li{display:flex;gap:12px;font-size:14.5px;align-items:flex-start;line-height:1.5}\n  .cmp li svg{flex:0 0 auto;width:18px;height:18px;margin-top:2px}\n  .cmp .them li{color:var(--muted)}\n  .cmp .them li svg{stroke:#ff5f56}\n  .cmp .us li{color:var(--ink)}\n  .cmp .us li svg{stroke:var(--gold)}\n\n  /* ---------- SECURITY / DEPLOY ---------- */\n  .deploy{background:linear-gradient(180deg,#f2f2ef,var(--bg))}\n  .dep-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:20px}\n  .dep{border:1px solid var(--line);border-radius:var(--r);padding:26px;background:var(--bg-2)}\n  .dep .ic{width:40px;height:40px;border-radius:10px;display:grid;place-items:center;background:var(--gold-dim);margin-bottom:16px}\n  .dep .ic svg{width:20px;height:20px;stroke:var(--gold)}\n  .dep h3{font-size:16px;margin-bottom:8px;font-weight:700}\n  .dep p{font-size:13.5px;color:var(--muted);line-height:1.5}\n\n  /* ---------- EXPERTS / TRUST ---------- */\n  .trust2{background:var(--bg);position:relative;overflow:hidden}\n  .trust2 .glow{position:absolute;left:-260px;bottom:-260px;width:760px;height:760px;border-radius:50%;background:radial-gradient(circle,rgba(46,111,242,.12),transparent 62%);filter:blur(24px);pointer-events:none}\n  .expert-grid{display:grid;grid-template-columns:1.05fr .95fr;gap:60px;align-items:center;position:relative;z-index:1}\n  .expert-copy h2{font-size:clamp(28px,4vw,46px);margin:18px 0 20px;letter-spacing:-.02em}\n  .expert-copy>p{color:var(--muted);font-size:17px;line-height:1.6;margin-bottom:34px;max-width:540px}\n  .pillars{display:grid;gap:22px}\n  .pillar{display:flex;gap:16px;align-items:flex-start}\n  .pillar .pic{flex:0 0 auto;width:44px;height:44px;border-radius:11px;display:grid;place-items:center;background:var(--gold-dim);border:1px solid var(--gold-dim)}\n  .pillar .pic svg{width:22px;height:22px;stroke:var(--gold)}\n  .pillar h4{font-size:16.5px;font-weight:700;margin-bottom:5px}\n  .pillar p{font-size:14.5px;color:var(--muted);line-height:1.55;max-width:430px}\n  .sec-panel{border:1px solid var(--line-2);border-radius:16px;background:linear-gradient(180deg,#ffffff,#f7f7f5);padding:30px;box-shadow:0 30px 80px -45px rgba(0,0,0,.9);position:relative;z-index:1}\n  .sec-panel .sp-top{display:flex;align-items:center;gap:13px;padding-bottom:20px;margin-bottom:22px;border-bottom:1px solid var(--line)}\n  .sec-panel .sp-top .shield{width:42px;height:42px;border-radius:11px;display:grid;place-items:center;background:radial-gradient(circle at 30% 25%,var(--gold-soft),var(--gold) 60%,#1d55d4);box-shadow:0 0 22px rgba(46,111,242,.35);flex:0 0 auto}\n  .sec-panel .sp-top .shield svg{width:22px;height:22px;stroke:#ffffff}\n  .sec-panel .sp-top h4{font-size:16px;font-weight:700}\n  .sec-panel .sp-top span{font-size:12.5px;color:var(--muted);display:block;margin-top:2px}\n  .sec-checks{display:grid;gap:14px}\n  .sec-checks li{display:flex;gap:11px;align-items:flex-start;font-size:14px;color:var(--ink);list-style:none}\n  .sec-checks li svg{flex:0 0 auto;width:18px;height:18px;stroke:var(--gold);margin-top:2px}\n  .sec-checks li b{font-weight:600}\n  .sec-checks li span{color:var(--muted)}\n  .sec-foot{margin-top:24px;padding-top:20px;border-top:1px solid var(--line);display:flex;align-items:center;gap:12px}\n  .sec-foot .nt{display:inline-flex;align-items:center;gap:9px;font-size:13px;color:var(--gold);font-weight:600;border:1px solid var(--gold-dim);background:var(--gold-dim);padding:8px 14px;border-radius:999px}\n  .sec-foot .nt svg{width:16px;height:16px;stroke:var(--gold)}\n\n  /* ---------- STATS BAND ---------- */\n  .band{background:var(--bg-2);border-top:1px solid var(--line);border-bottom:1px solid var(--line)}\n  .band .wrap{display:grid;grid-template-columns:repeat(4,1fr);gap:30px;padding-top:70px;padding-bottom:70px}\n  .stat{text-align:center}\n  .stat b{display:block;font-size:58px;font-weight:400;letter-spacing:-.01em;font-family:var(--serif);background:linear-gradient(180deg,var(--ink),var(--gold));-webkit-background-clip:text;background-clip:text;-webkit-text-fill-color:transparent}\n  .stat span{font-size:14px;color:var(--muted)}\n\n  /* ---------- QUOTE ---------- */\n  .quote{background:var(--bg);text-align:center}\n  .quote blockquote{max-width:860px;margin:0 auto;font-family:var(--serif);font-size:clamp(26px,3.8vw,42px);font-weight:400;letter-spacing:-.01em;line-height:1.28}\n  .quote blockquote .gold{font-style:normal}\n  .quote .qattr{margin-top:30px;color:var(--muted);font-size:14px}\n  .quote .qmark{font-size:80px;color:var(--gold);line-height:.4;font-family:Georgia,serif;opacity:.5}\n\n  /* ---------- FAQ ---------- */\n  .faq{background:linear-gradient(180deg,var(--bg),#f2f2ef)}\n  .faq-list{max-width:840px;margin:0 auto;display:grid;gap:0;border-top:1px solid var(--line)}\n  .qa{border-bottom:1px solid var(--line)}\n  .qa button{width:100%;background:none;border:0;color:var(--ink);text-align:left;display:flex;justify-content:space-between;gap:20px;align-items:center;padding:26px 4px;cursor:pointer;font-size:18px;font-weight:600;font-family:inherit}\n  .qa button .pm{flex:0 0 auto;width:24px;height:24px;display:grid;place-items:center;border:1px solid var(--line-2);border-radius:50%;color:var(--gold);transition:.25s;font-size:18px}\n  .qa.open button .pm{transform:rotate(45deg);background:var(--gold);color:#ffffff;border-color:var(--gold)}\n  .qa .ans{max-height:0;overflow:hidden;transition:max-height .3s ease;color:var(--muted);font-size:15.5px;line-height:1.6}\n  .qa .ans p{padding:0 4px 26px;max-width:720px}\n\n  /* ---------- CTA ---------- */\n  .cta{position:relative;overflow:hidden;background:var(--bg);text-align:center;padding:130px 0}\n  .cta .glow{position:absolute;left:50%;top:50%;transform:translate(-50%,-50%);width:760px;height:760px;border-radius:50%;background:radial-gradient(circle,rgba(46,111,242,.16),transparent 60%);filter:blur(30px)}\n  .cta-in{position:relative;z-index:2}\n  .cta h2{font-size:clamp(38px,6vw,72px);font-weight:400;letter-spacing:-.01em;margin:20px auto 22px;max-width:800px}\n  .cta h2 .gold{display:block}\n  .cta p{color:var(--muted);font-size:19px;max-width:540px;margin:0 auto 38px}\n  .cta-row{display:flex;gap:14px;justify-content:center;flex-wrap:wrap}\n  .cta .fine{margin-top:24px;font-size:13px;color:var(--muted-2)}\n\n  /* ---------- FOOTER ---------- */\n  footer{background:#f2f2ef;border-top:1px solid var(--line);padding:64px 0 38px}\n  .foot-grid{display:grid;grid-template-columns:1.6fr 1fr 1fr 1fr;gap:40px;margin-bottom:48px}\n  .foot-brand p{color:var(--muted);font-size:14px;margin-top:16px;max-width:280px;line-height:1.6}\n  .foot-col h4{font-size:12px;letter-spacing:.16em;text-transform:uppercase;color:var(--muted-2);margin-bottom:18px;font-family:var(--mono)}\n  .foot-col a{display:block;color:var(--muted);font-size:14px;margin-bottom:12px;transition:.2s}\n  .foot-col a:hover{color:var(--gold)}\n  .foot-bot{display:flex;justify-content:space-between;align-items:center;border-top:1px solid var(--line);padding-top:26px;flex-wrap:wrap;gap:16px}\n  .foot-bot p{color:var(--muted-2);font-size:13px}\n  .foot-bot .made{font-family:var(--mono);font-size:12px;color:var(--muted-2)}\n\n  /* reveal */\n  .reveal{opacity:0;transform:translateY(24px);transition:opacity .7s cubic-bezier(.2,.7,.2,1),transform .7s cubic-bezier(.2,.7,.2,1)}\n  .reveal.in{opacity:1;transform:none}\n\n  /* ---------- RESPONSIVE ---------- */\n  @media(max-width:980px){\n    .prob-grid,.feat-grid,.ind-grid,.src-groups{grid-template-columns:1fr 1fr}\n    .dep-grid{grid-template-columns:1fr 1fr}\n    .show-grid,.expert-grid{grid-template-columns:1fr;gap:38px}\n    .band .wrap{grid-template-columns:1fr 1fr;gap:40px}\n    .hero-fade{background:linear-gradient(180deg,rgba(250,250,248,.4),rgba(250,250,248,.88))}\n  }\n  @media(max-width:680px){\n    .nav-links{display:none}\n    .prob-grid,.feat-grid,.ind-grid,.dep-grid,.cmp,.src-groups{grid-template-columns:1fr}\n    .cmp .col.them{border-right:0;border-bottom:1px solid var(--line)}\n    .layer{grid-template-columns:1fr;gap:14px}\n    .layer .lnum b{font-size:36px}\n    section{padding:78px 0}\n    .hero-meta{gap:24px}\n    .nav-cta .btn-ghost{display:none}\n    .foot-grid{grid-template-columns:1fr 1fr}\n  }\n</style>\n</head>\n<body>\n\n<!-- NAV -->\n<header class=\"nav\" id=\"nav\">\n  <div class=\"nav-in\">\n    <a href=\"#top\" class=\"brand\" aria-label=\"Endurance AI Labs — Brain\">\n      <img src=\"/logo-endurance.svg\" alt=\"Endurance AI Labs\" class=\"wordmark\" />\n      <span class=\"bdiv\"></span>\n      <span class=\"bprod\">Brain</span>\n    </a>\n    <nav class=\"nav-links\">\n      <a href=\"#how\">How it works</a>\n      <a href=\"#features\">Capabilities</a>\n      <a href=\"#industries\">Industries</a>\n      <a href=\"#versus\">Why it's different</a>\n      <a href=\"#security\">Security</a>\n      <a href=\"#faq\">FAQ</a>\n      <a href=\"/brain/reel\" class=\"nav-reel\">▶ Watch the reel</a>\n    </nav>\n    <div class=\"nav-cta\">\n      <a href=\"#\" data-demo class=\"btn btn-ghost\">Book a demo</a>\n      <a href=\"#cta\" class=\"btn btn-gold\">Get started</a>\n    </div>\n  </div>\n</header>\n\n<!-- HERO -->\n<section class=\"hero\" id=\"top\">\n  <canvas id=\"net\"></canvas>\n  <div class=\"hero-glow\"></div>\n  <div class=\"hero-fade\"></div>\n  <div class=\"hero-in\">\n    <div class=\"wrap\">\n      <div class=\"hero-grid\">\n        <p class=\"coords\" style=\"margin-bottom:20px\">68°44′21″S <span class=\"dot\">·</span> 52°19′47″W — Endurance, found intact after 107 years</p>\n        <span class=\"tag\"><span class=\"pip\"></span><span>Institutional memory · powered by Endurance AI Labs</span></span>\n        <h1>Institutional memory,<br><span class=\"l2\">finally autonomous.</span></h1>\n        <p class=\"sub\">Every email, message, document, meeting, deal, and line of code your firm produces flows into a living knowledge base that <strong>maintains itself</strong> — and answers any question with <strong>cited, verifiable</strong> sources. No more knowledge walking out the door.</p>\n        <div class=\"hero-cta\">\n          <a href=\"#cta\" class=\"btn btn-gold\">Deploy your Brain &nbsp;→</a>\n          <a href=\"#how\" class=\"btn btn-ghost\">See how it works</a>\n        </div>\n        <div class=\"hero-meta\">\n          <div class=\"m\"><b>20+</b><span>data sources, unified</span></div>\n          <div class=\"m\"><b>100%</b><span>cited — zero hallucination</span></div>\n          <div class=\"m\"><b>24/7</b><span>self-maintaining</span></div>\n        </div>\n      </div>\n    </div>\n  </div>\n  <div class=\"scroll-hint\">scroll ↓</div>\n</section>\n\n<!-- TRUST / SOURCES -->\n<div class=\"trust\">\n  <div class=\"wrap\">\n    <p class=\"lbl\"><b>One brain. Every system your team already lives in.</b></p>\n    <p class=\"lsub\">Connectors ingest from the tools your firm runs on today — and the modular layer means anything with an API can plug in.</p>\n    <div class=\"src-groups\">\n\n      <div class=\"src-cat\">\n        <h5>Communication</h5>\n        <div class=\"chips\">\n          <span>Email / Outlook / Exchange</span>\n          <span>Gmail &amp; Google Groups</span>\n          <span>Slack</span>\n          <span>Microsoft Teams</span>\n          <span>SMS &amp; WhatsApp Business</span>\n          <span>Intercom</span>\n        </div>\n      </div>\n\n      <div class=\"src-cat\">\n        <h5>Documents &amp; Files</h5>\n        <div class=\"chips\">\n          <span>Google Drive &amp; Docs</span>\n          <span>SharePoint &amp; OneDrive</span>\n          <span>Box</span>\n          <span>Dropbox</span>\n          <span>PDFs &amp; file shares</span>\n          <span>DocuSign &amp; contracts</span>\n        </div>\n      </div>\n\n      <div class=\"src-cat\">\n        <h5>Knowledge &amp; Wikis</h5>\n        <div class=\"chips\">\n          <span>Confluence</span>\n          <span>Notion</span>\n          <span>Guru</span>\n          <span>SharePoint wikis</span>\n          <span>Internal wikis</span>\n        </div>\n      </div>\n\n      <div class=\"src-cat\">\n        <h5>Projects &amp; Tickets</h5>\n        <div class=\"chips\">\n          <span>Jira</span>\n          <span>Asana</span>\n          <span>Linear</span>\n          <span>Monday.com</span>\n          <span>ClickUp</span>\n          <span>Trello</span>\n          <span>ServiceNow</span>\n          <span>Zendesk</span>\n        </div>\n      </div>\n\n      <div class=\"src-cat\">\n        <h5>Meetings &amp; Calls</h5>\n        <div class=\"chips\">\n          <span>Zoom transcripts</span>\n          <span>Google Meet</span>\n          <span>Teams meetings</span>\n          <span>Gong</span>\n          <span>Fireflies</span>\n          <span>Otter.ai</span>\n          <span>Calendars</span>\n        </div>\n      </div>\n\n      <div class=\"src-cat\">\n        <h5>CRM &amp; Business Systems</h5>\n        <div class=\"chips\">\n          <span>Salesforce</span>\n          <span>HubSpot</span>\n          <span>NetSuite / ERP</span>\n          <span>Airtable</span>\n          <span>SAP &amp; Oracle</span>\n        </div>\n      </div>\n\n      <div class=\"src-cat\">\n        <h5>Deal Rooms &amp; Industry DMS</h5>\n        <div class=\"chips\">\n          <span>Datasite</span>\n          <span>Intralinks</span>\n          <span>iManage</span>\n          <span>NetDocuments</span>\n          <span>Virtual data rooms</span>\n        </div>\n      </div>\n\n      <div class=\"src-cat\">\n        <h5>Code &amp; Engineering</h5>\n        <div class=\"chips\">\n          <span>GitHub</span>\n          <span>GitLab</span>\n          <span>Bitbucket</span>\n          <span>Azure DevOps</span>\n        </div>\n      </div>\n\n    </div>\n    <p class=\"src-foot\">Don't see yours? <a href=\"#cta\" class=\"gold\" style=\"font-weight:600\">If it has an API, the Brain can ingest it →</a></p>\n  </div>\n</div>\n\n<!-- PROBLEM -->\n<section class=\"problem\" id=\"problem\">\n  <div class=\"wrap\">\n    <div class=\"sec-head reveal\">\n      <span class=\"eyebrow\"><span class=\"dot\">●</span> The problem</span>\n      <h2>Your firm's most valuable asset is its memory. And it's leaking.</h2>\n      <p>The context behind every deal, matter, shipment, and decision lives scattered across a dozen tools and a handful of people's heads. When they're busy, on PTO, or gone — that knowledge is gone with them.</p>\n    </div>\n    <div class=\"prob-grid\">\n      <div class=\"prob-card reveal\">\n        <div class=\"n\">01 / KNOWLEDGE SILOS</div>\n        <h3>Answers are buried</h3>\n        <p>The thread, the doc, the email, the meeting where it was actually decided — nobody can find it. Teams re-litigate solved problems weekly.</p>\n      </div>\n      <div class=\"prob-card reveal\">\n        <div class=\"n\">02 / TRIBAL KNOWLEDGE</div>\n        <h3>It walks out the door</h3>\n        <p>When a partner, PM, or senior associate leaves, years of context leaves with them. Onboarding the next hire takes months instead of days.</p>\n      </div>\n      <div class=\"prob-card reveal\">\n        <div class=\"n\">03 / AI YOU CAN'T TRUST</div>\n        <h3>Chatbots that hallucinate</h3>\n        <p>Generic AI search confidently invents facts with no source. In law, finance, and real estate, an unverifiable answer is worse than none.</p>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- HOW IT WORKS -->\n<section class=\"how\" id=\"how\">\n  <div class=\"wrap\">\n    <div class=\"sec-head center reveal\">\n      <span class=\"eyebrow\"><span class=\"dot\">●</span> How it works</span>\n      <h2>Three layers. One compounding brain.</h2>\n      <p>Built on Andrej Karpathy's LLM-Wiki pattern — proven in production, not a science project. Raw truth at the bottom, living synthesis on top, a strict schema in between.</p>\n    </div>\n    <div class=\"layers\">\n      <div class=\"layer reveal\">\n        <div class=\"lnum\">LAYER<b>01</b></div>\n        <div>\n          <h3>Ingest — immutable raw sources</h3>\n          <p>Connectors pull from every tool your team uses and write them into a permanent, tamper-proof record. The source of truth is never overwritten or paraphrased — it's preserved verbatim, forever.</p>\n          <span class=\"lpill\">Email · Slack · Docs · Jira · Confluence · Zoom · Code · CRM</span>\n        </div>\n      </div>\n      <div class=\"flowline\"></div>\n      <div class=\"layer reveal\">\n        <div class=\"lnum\">LAYER<b>02</b></div>\n        <div>\n          <h3>Synthesize — the living wiki</h3>\n          <p>An LLM continuously maintains entity pages (people, clients, deals, projects, properties) and synthesis pages (expertise maps, onboarding guides, Q&amp;A). Every claim is backed by a citation to a raw source — enforced by schema, not hope.</p>\n          <span class=\"lpill\">Entity pages · Synthesis pages · Citation-enforced</span>\n        </div>\n      </div>\n      <div class=\"flowline\"></div>\n      <div class=\"layer reveal\">\n        <div class=\"lnum\">LAYER<b>03</b></div>\n        <div>\n          <h3>Answer — ask in plain language</h3>\n          <p>Your team asks questions in Slack, the web, or your tools of choice. The Brain reads the compiled wiki and answers with linked sources every time. A deterministic lint loop hunts contradictions and stale facts so the brain only gets sharper.</p>\n          <span class=\"lpill\">Chat interface · Verifiable answers · Self-healing lint</span>\n        </div>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- CAPABILITIES -->\n<section class=\"features\" id=\"features\">\n  <div class=\"wrap\">\n    <div class=\"sec-head reveal\">\n      <span class=\"eyebrow\"><span class=\"dot\">●</span> Capabilities</span>\n      <h2>Everything a knowledge base should have been all along.</h2>\n      <p>Not a search box bolted onto your data. A structured, self-governing system designed so the answers are trustworthy by construction.</p>\n    </div>\n    <div class=\"feat-grid\">\n      <div class=\"feat reveal\">\n        <div class=\"ic\"><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-link\"/></svg></div>\n        <h3>Citations on every claim</h3>\n        <p>No statement reaches your team without a link to the exact email, message, or document it came from. Trust, then verify — in one click.</p>\n      </div>\n      <div class=\"feat reveal\">\n        <div class=\"ic\"><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-person\"/></svg></div>\n        <h3>Entity pages</h3>\n        <p>A living profile for every person, client, deal, property, vendor, and project — auto-assembled from everything they've touched across your stack.</p>\n      </div>\n      <div class=\"feat reveal\">\n        <div class=\"ic\"><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-layers\"/></svg></div>\n        <h3>Synthesis pages</h3>\n        <p>Expertise maps, onboarding guides, and curated Q&amp;A compiled by the LLM and kept current — the institutional knowledge you wish you'd written down.</p>\n      </div>\n      <div class=\"feat reveal\">\n        <div class=\"ic\"><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-refresh\"/></svg></div>\n        <h3>Self-maintaining</h3>\n        <p>Scheduled syncs ingest new activity around the clock and re-compile the wiki automatically. The brain stays current with zero manual upkeep.</p>\n      </div>\n      <div class=\"feat reveal\">\n        <div class=\"ic\"><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-shield\"/></svg></div>\n        <h3>Deterministic lint</h3>\n        <p>A rules engine continuously scans for contradictions, stale data, and unbacked claims — flagging them before they ever mislead a decision.</p>\n      </div>\n      <div class=\"feat reveal\">\n        <div class=\"ic\"><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-scale\"/></svg></div>\n        <h3>Authority &amp; conflict rules</h3>\n        <p>When sources disagree, a strict precedence decides what wins — and the brain surfaces the discrepancy instead of silently guessing.</p>\n      </div>\n      <div class=\"feat reveal\">\n        <div class=\"ic\"><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-chat\"/></svg></div>\n        <h3>Ask anywhere</h3>\n        <p>Query the brain from Slack, Teams, the web app, or embed it in your own tools. Chat-style answers land where your team already works.</p>\n      </div>\n      <div class=\"feat reveal\">\n        <div class=\"ic\"><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-clock\"/></svg></div>\n        <h3>Onboard in days, not months</h3>\n        <p>New hires read one onboarding guide that's always up to date — and ask the brain everything else. Time-to-productive drops dramatically.</p>\n      </div>\n      <div class=\"feat reveal\">\n        <div class=\"ic\"><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-plug\"/></svg></div>\n        <h3>Extensible connectors</h3>\n        <p>Add a new source and the brain absorbs it. Connectors are modular — your DMS, ERP, deal room, or proprietary system plugs right in.</p>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- CITATION SHOWCASE -->\n<section class=\"showcase\" id=\"showcase\">\n  <div class=\"wrap\">\n    <div class=\"show-grid\">\n      <div class=\"show-copy reveal\">\n        <span class=\"eyebrow\"><span class=\"dot\">●</span> Trust by construction</span>\n        <h2>If it can't cite it, it won't claim it.</h2>\n        <p>Endurance Brain was built around a single hard rule: <strong style=\"color:var(--ink)\">every fact must trace to a real source.</strong> The schema rejects any synthesized claim that isn't backed by a link to the underlying email, thread, ticket, or document.</p>\n        <ul class=\"show-list\">\n          <li><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-check\"/></svg><span>Born from a real failure mode — an early system once invented a profile from a job title with zero evidence. The citation rule exists so that can never happen silently again.</span></li>\n          <li><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-check\"/></svg><span>When evidence is thin, the brain <em>says so</em> rather than filling the gap with confident fiction.</span></li>\n          <li><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-check\"/></svg><span>Every answer is one click from the primary source — perfect for legal, financial, and regulated work.</span></li>\n        </ul>\n      </div>\n      <div class=\"terminal reveal\">\n        <div class=\"term-bar\"><i></i><i></i><i></i><span>ask · endurance-brain</span></div>\n        <div class=\"term-body\">\n<span class=\"q\">&gt; Who owns the Riverside acquisition and what's the latest?</span><br><br>\n<span class=\"a\">The Riverside acquisition is led by <b>D. Marsh</b> (Acquisitions).</span><br>\n<span class=\"dim\">  ↳ source: </span><span class=\"cite\">[[email/2026-05-tour-recap]]</span><br>\n<span class=\"a\">LOI signed 5/28; DD closes 6/20. Survey flagged an</span><br>\n<span class=\"a\">easement on the north parcel — open item.</span><br>\n<span class=\"dim\">  ↳ source: </span><span class=\"cite\">[[deal-room/Riverside#DD]]</span><br>\n<span class=\"dim\">  ↳ source: </span><span class=\"cite\">[[meeting/2026-06-09-IC]]</span><br><br>\n<span class=\"ok\">✓ 3 claims · 3 cited · 0 unverified</span><br>\n<span class=\"dim\">  lint: no contradictions · sources current</span>\n        </div>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- INDUSTRIES -->\n<section class=\"industries\" id=\"industries\">\n  <div class=\"wrap\">\n    <div class=\"sec-head center reveal\">\n      <span class=\"eyebrow\"><span class=\"dot\">●</span> Built for knowledge-heavy firms</span>\n      <h2>One brain. Every industry that runs on memory.</h2>\n      <p>Wherever decisions depend on context spread across people and tools, Endurance Brain becomes the system of record your team can finally trust.</p>\n    </div>\n    <div class=\"ind-grid\">\n\n      <div class=\"ind reveal\">\n        <div class=\"ihead\"><span class=\"iic\"><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-scale\"/></svg></span><h3>Law Firms</h3></div>\n        <p>Turn every matter, brief, email, and deposition into instantly-searchable, cited institutional knowledge.</p>\n        <ul>\n          <li>Matter &amp; client history at a glance</li>\n          <li>Precedent &amp; clause retrieval with sources</li>\n          <li>Conflict checks across communications</li>\n          <li>Associate onboarding in days</li>\n        </ul>\n      </div>\n\n      <div class=\"ind reveal\">\n        <div class=\"ihead\"><span class=\"iic\"><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-building\"/></svg></span><h3>Real Estate</h3></div>\n        <p>Every deal, property, lease, and lender conversation unified into one living deal-memory.</p>\n        <ul>\n          <li>Per-property &amp; per-deal entity pages</li>\n          <li>Underwriting context &amp; DD status</li>\n          <li>Broker, lender &amp; partner relationship history</li>\n          <li>IC memos backed by cited sources</li>\n        </ul>\n      </div>\n\n      <div class=\"ind reveal\">\n        <div class=\"ihead\"><span class=\"iic\"><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-truck\"/></svg></span><h3>Logistics &amp; Supply Chain</h3></div>\n        <p>Carriers, lanes, SOPs, and exceptions captured so operational knowledge never ships out the door.</p>\n        <ul>\n          <li>Carrier &amp; vendor performance memory</li>\n          <li>Lane &amp; route playbooks, always current</li>\n          <li>Incident &amp; exception history with root cause</li>\n          <li>SOPs that update themselves</li>\n        </ul>\n      </div>\n\n      <div class=\"ind reveal\">\n        <div class=\"ihead\"><span class=\"iic\"><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-rocket\"/></svg></span><h3>Venture Capital</h3></div>\n        <p>Founders, deals, diligence, and portfolio context compiled into a fund-wide memory.</p>\n        <ul>\n          <li>Company &amp; founder dossiers, auto-built</li>\n          <li>Deal pipeline &amp; pass-reason history</li>\n          <li>Portfolio updates synthesized continuously</li>\n          <li>Warm-intro &amp; relationship graph</li>\n        </ul>\n      </div>\n\n      <div class=\"ind reveal\">\n        <div class=\"ihead\"><span class=\"iic\"><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-chart\"/></svg></span><h3>Private Equity</h3></div>\n        <p>Diligence, portfolio operations, and LP context in one auditable, cited knowledge base.</p>\n        <ul>\n          <li>Target &amp; portfo­lio-company entity pages</li>\n          <li>Diligence findings with source trails</li>\n          <li>Value-creation plan tracking</li>\n          <li>LP &amp; deal-team institutional memory</li>\n        </ul>\n      </div>\n\n      <div class=\"ind reveal\">\n        <div class=\"ihead\"><span class=\"iic\"><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-bank\"/></svg></span><h3>Financial Services</h3></div>\n        <p>Research, client relationships, and compliance context unified with full audit trails.</p>\n        <ul>\n          <li>Client &amp; account history, cited</li>\n          <li>Research &amp; thesis synthesis</li>\n          <li>Audit-ready, immutable records</li>\n          <li>Cross-desk knowledge sharing</li>\n        </ul>\n      </div>\n\n      <div class=\"ind reveal\">\n        <div class=\"ihead\"><span class=\"iic\"><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-briefcase\"/></svg></span><h3>Consulting &amp; Pro Services</h3></div>\n        <p>Every engagement, deliverable, and SME becomes reusable, attributable firm IP.</p>\n        <ul>\n          <li>Engagement &amp; client knowledge bases</li>\n          <li>Expertise maps — find the right SME fast</li>\n          <li>Reusable methodology &amp; deliverables</li>\n          <li>Proposal context at your fingertips</li>\n        </ul>\n      </div>\n\n      <div class=\"ind reveal\">\n        <div class=\"ihead\"><span class=\"iic\"><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-heart\"/></svg></span><h3>Healthcare &amp; Life Sciences</h3></div>\n        <p>Protocols, research, and operational knowledge kept current and fully traceable.</p>\n        <ul>\n          <li>Protocol &amp; SOP knowledge base</li>\n          <li>Research &amp; trial context synthesis</li>\n          <li>Traceable, compliance-friendly answers</li>\n          <li>Cross-team continuity of care knowledge</li>\n        </ul>\n      </div>\n\n      <div class=\"ind reveal\">\n        <div class=\"ihead\"><span class=\"iic\"><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-cpu\"/></svg></span><h3>Engineering &amp; Manufacturing</h3></div>\n        <p>Specs, decisions, incidents, and tribal know-how captured before the experts retire.</p>\n        <ul>\n          <li>System &amp; product entity pages</li>\n          <li>Design-decision &amp; rationale history</li>\n          <li>Incident &amp; RCA knowledge base</li>\n          <li>Onboard engineers against living docs</li>\n        </ul>\n      </div>\n\n      <div class=\"ind reveal\">\n        <div class=\"ihead\"><span class=\"iic\"><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-handshake\"/></svg></span><h3>Investment Banking &amp; M&amp;A</h3></div>\n        <p>Live deal context, precedent transactions, and counterparty history compiled across every workstream.</p>\n        <ul>\n          <li>Deal &amp; counterparty entity pages</li>\n          <li>Precedent transaction memory</li>\n          <li>Data-room &amp; diligence synthesis</li>\n          <li>Pitch &amp; CIM context, cited</li>\n        </ul>\n      </div>\n\n      <div class=\"ind reveal\">\n        <div class=\"ihead\"><span class=\"iic\"><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-calculator\"/></svg></span><h3>Accounting &amp; Audit</h3></div>\n        <p>Engagements, workpapers, and client history turned into a traceable, audit-ready knowledge base.</p>\n        <ul>\n          <li>Client &amp; engagement entity pages</li>\n          <li>Workpaper &amp; treatment precedent</li>\n          <li>Full source trail for every figure</li>\n          <li>Staff onboarding against live guidance</li>\n        </ul>\n      </div>\n\n      <div class=\"ind reveal\">\n        <div class=\"ihead\"><span class=\"iic\"><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-umbrella\"/></svg></span><h3>Insurance</h3></div>\n        <p>Policies, claims, underwriting notes, and broker relationships unified into one cited memory.</p>\n        <ul>\n          <li>Policyholder &amp; claim entity pages</li>\n          <li>Underwriting precedent &amp; rationale</li>\n          <li>Claims history with source trail</li>\n          <li>Broker &amp; carrier relationship memory</li>\n        </ul>\n      </div>\n\n      <div class=\"ind reveal\">\n        <div class=\"ihead\"><span class=\"iic\"><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-gem\"/></svg></span><h3>Wealth Mgmt &amp; Family Offices</h3></div>\n        <p>Client relationships, holdings, and decisions captured into discreet, fully-cited institutional memory.</p>\n        <ul>\n          <li>Household &amp; entity relationship maps</li>\n          <li>Investment decision &amp; rationale history</li>\n          <li>Advisor continuity across staff changes</li>\n          <li>Discreet, private deployment</li>\n        </ul>\n      </div>\n\n      <div class=\"ind reveal\">\n        <div class=\"ihead\"><span class=\"iic\"><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-ruler\"/></svg></span><h3>Architecture &amp; Construction</h3></div>\n        <p>Every project, RFI, submittal, and change order captured before it scatters across email and drives.</p>\n        <ul>\n          <li>Per-project &amp; per-site entity pages</li>\n          <li>RFI, submittal &amp; change-order history</li>\n          <li>Spec &amp; design-decision rationale</li>\n          <li>Subcontractor performance memory</li>\n        </ul>\n      </div>\n\n      <div class=\"ind reveal\">\n        <div class=\"ihead\"><span class=\"iic\"><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-cloud\"/></svg></span><h3>Technology &amp; SaaS</h3></div>\n        <p>Product decisions, customer context, and engineering knowledge in one self-maintaining brain.</p>\n        <ul>\n          <li>Customer &amp; account entity pages</li>\n          <li>Product &amp; roadmap decision history</li>\n          <li>Engineering &amp; incident knowledge</li>\n          <li>Support &amp; success context, unified</li>\n        </ul>\n      </div>\n\n      <div class=\"ind reveal\">\n        <div class=\"ihead\"><span class=\"iic\"><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-landmark\"/></svg></span><h3>Government &amp; Public Sector</h3></div>\n        <p>Programs, contracts, and institutional knowledge preserved across administrations and turnover.</p>\n        <ul>\n          <li>Program &amp; contract entity pages</li>\n          <li>Policy &amp; decision provenance</li>\n          <li>Continuity across staff turnover</li>\n          <li>Auditable, traceable answers</li>\n        </ul>\n      </div>\n\n      <div class=\"ind reveal\">\n        <div class=\"ihead\"><span class=\"iic\"><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-bolt\"/></svg></span><h3>Energy &amp; Utilities</h3></div>\n        <p>Assets, projects, regulatory filings, and field knowledge captured into a durable, cited record.</p>\n        <ul>\n          <li>Asset &amp; site entity pages</li>\n          <li>Project &amp; permitting history</li>\n          <li>Regulatory &amp; compliance trail</li>\n          <li>Field &amp; operational know-how retained</li>\n        </ul>\n      </div>\n\n      <div class=\"ind reveal\">\n        <div class=\"ihead\"><span class=\"iic\"><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-megaphone\"/></svg></span><h3>Media &amp; Agencies</h3></div>\n        <p>Clients, campaigns, and creative decisions become reusable, attributable agency IP.</p>\n        <ul>\n          <li>Client &amp; campaign entity pages</li>\n          <li>Creative brief &amp; decision history</li>\n          <li>Reusable playbooks &amp; case studies</li>\n          <li>Pitch context at your fingertips</li>\n        </ul>\n      </div>\n\n    </div>\n    <p style=\"text-align:center;margin-top:38px;color:var(--muted);font-size:15px\" class=\"reveal\">Also: Pharma &amp; Biotech · Asset Management · Nonprofits &amp; Foundations · Education &amp; Research · Hospitality · Telecom — <a href=\"#cta\" class=\"gold\" style=\"font-weight:600\">if your firm runs on knowledge, the Brain fits →</a></p>\n  </div>\n</section>\n\n<!-- VERSUS -->\n<section class=\"versus\" id=\"versus\">\n  <div class=\"wrap\">\n    <div class=\"sec-head center reveal\">\n      <span class=\"eyebrow\"><span class=\"dot\">●</span> Why it's different</span>\n      <h2>Not another RAG chatbot.</h2>\n      <p>Most \"AI knowledge\" tools embed your documents and hope the model retrieves the right chunk. Endurance Brain is a governed system of record — structured, cited, and self-correcting.</p>\n    </div>\n    <div class=\"cmp reveal\">\n      <div class=\"col them\">\n        <h3>Generic AI search / RAG</h3>\n        <ul>\n          <li><svg fill=\"none\" stroke-width=\"2.2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-x\"/></svg>Confidently hallucinates with no source</li>\n          <li><svg fill=\"none\" stroke-width=\"2.2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-x\"/></svg>Opaque vector blobs you can't read or audit</li>\n          <li><svg fill=\"none\" stroke-width=\"2.2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-x\"/></svg>Re-embeds everything; quietly drifts stale</li>\n          <li><svg fill=\"none\" stroke-width=\"2.2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-x\"/></svg>No notion of conflicting sources</li>\n          <li><svg fill=\"none\" stroke-width=\"2.2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-x\"/></svg>Ships your data to someone else's cloud</li>\n        </ul>\n      </div>\n      <div class=\"col us\">\n        <h3>Endurance Brain</h3>\n        <ul>\n          <li><svg fill=\"none\" stroke-width=\"2.2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-check\"/></svg>Every claim cites a verifiable source — or isn't made</li>\n          <li><svg fill=\"none\" stroke-width=\"2.2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-check\"/></svg>Human-readable wiki you fully own and audit</li>\n          <li><svg fill=\"none\" stroke-width=\"2.2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-check\"/></svg>Self-maintaining syncs keep it permanently current</li>\n          <li><svg fill=\"none\" stroke-width=\"2.2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-check\"/></svg>Authority rules resolve &amp; surface conflicts</li>\n          <li><svg fill=\"none\" stroke-width=\"2.2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-check\"/></svg>Runs private, on your own infrastructure</li>\n        </ul>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- SECURITY / DEPLOY -->\n<section class=\"deploy\" id=\"security\">\n  <div class=\"wrap\">\n    <div class=\"sec-head reveal\">\n      <span class=\"eyebrow\"><span class=\"dot\">●</span> Security &amp; deployment</span>\n      <h2>Your knowledge. Your infrastructure. Your control.</h2>\n      <p>Endurance Brain runs entirely within your environment. Sensitive source material never leaves your perimeter, and you own every byte of the wiki it produces.</p>\n    </div>\n    <div class=\"dep-grid\">\n      <div class=\"dep reveal\">\n        <div class=\"ic\"><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-server\"/></svg></div>\n        <h3>Self-hosted</h3>\n        <p>Deploys to your cloud or on-prem. Single-instance to enterprise — your call, your tenancy.</p>\n      </div>\n      <div class=\"dep reveal\">\n        <div class=\"ic\"><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-lock\"/></svg></div>\n        <h3>Private by default</h3>\n        <p>Raw source material stays inside your perimeter. Nothing is shared outside the team.</p>\n      </div>\n      <div class=\"dep reveal\">\n        <div class=\"ic\"><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-key\"/></svg></div>\n        <h3>Your credentials</h3>\n        <p>Connectors use your own API tokens with read-only scopes. Least-privilege from day one.</p>\n      </div>\n      <div class=\"dep reveal\">\n        <div class=\"ic\"><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-git\"/></svg></div>\n        <h3>Versioned &amp; auditable</h3>\n        <p>The wiki is plain, version-controlled files. Every change is tracked, diffable, reversible.</p>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- EXPERTS / WORLD-CLASS SECURITY -->\n<section class=\"trust2\" id=\"experts\">\n  <div class=\"glow\"></div>\n  <div class=\"wrap\">\n    <div class=\"expert-grid\">\n      <div class=\"expert-copy reveal\">\n        <span class=\"eyebrow\"><span class=\"dot\">●</span> World-class team · institutional-grade security</span>\n        <h2>Built by AI experts who've secured institutional-grade systems.</h2>\n        <p>Endurance Brain is engineered by a team that has spent its career building secure, mission-critical software for institutional-quality firms — where a single leaked record or unverifiable answer isn't an inconvenience, it's a liability. Security isn't a feature we added. It's the discipline the whole system is built on.</p>\n        <div class=\"pillars\">\n          <div class=\"pillar\">\n            <span class=\"pic\"><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-award\"/></svg></span>\n            <div><h4>Institutional pedigree</h4><p>A team with deep experience delivering software to law firms, financial institutions, and other regulated, high-stakes environments — where the security bar is set by the most demanding clients in the world.</p></div>\n          </div>\n          <div class=\"pillar\">\n            <span class=\"pic\"><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-shield\"/></svg></span>\n            <div><h4>Security-first engineering</h4><p>Defense-in-depth, least-privilege access, and a deny-by-default posture are baked into the architecture from the first line of code — not bolted on after launch.</p></div>\n          </div>\n          <div class=\"pillar\">\n            <span class=\"pic\"><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-radar\"/></svg></span>\n            <div><h4>AI you can actually trust</h4><p>The same rigor that powers the citation engine governs the system itself — every action is logged, attributable, and auditable, so you always know what the Brain accessed and why.</p></div>\n          </div>\n        </div>\n      </div>\n\n      <div class=\"sec-panel reveal\">\n        <div class=\"sp-top\">\n          <span class=\"shield\"><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-lock\"/></svg></span>\n          <div><h4>Enterprise security posture</h4><span>How your knowledge stays protected</span></div>\n        </div>\n        <ul class=\"sec-checks\">\n          <li><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-check\"/></svg><span><b>Runs in your environment</b> — self-hosted on your cloud or on-prem; data never leaves your perimeter.</span></li>\n          <li><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-check\"/></svg><span><b>Encrypted in transit &amp; at rest</b> — modern encryption everywhere your knowledge lives and moves.</span></li>\n          <li><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-check\"/></svg><span><b>Least-privilege connectors</b> — every integration uses your own read-only, scoped credentials.</span></li>\n          <li><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-check\"/></svg><span><b>Role-based access &amp; SSO-ready</b> — control exactly who can query and see what.</span></li>\n          <li><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-check\"/></svg><span><b>Immutable audit trail</b> — an append-only record of every ingest, answer, and change.</span></li>\n          <li><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-check\"/></svg><span><b>Single-tenant isolation</b> — your Brain is yours alone; never co-mingled with another firm's data.</span></li>\n          <li><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-check\"/></svg><span><b>Compliance-ready architecture</b> — designed to support the controls regulated industries require.</span></li>\n        </ul>\n        <div class=\"sec-foot\">\n          <span class=\"nt\"><svg fill=\"none\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><use href=\"#i-eyeoff\"/></svg>Your data is never used to train external models</span>\n        </div>\n      </div>\n\n    </div>\n  </div>\n</section>\n\n<!-- STATS BAND -->\n<div class=\"band\">\n  <div class=\"wrap\">\n    <div class=\"stat reveal\"><b>20+</b><span>integrated sources, unified</span></div>\n    <div class=\"stat reveal\"><b>100%</b><span>of claims carry a citation</span></div>\n    <div class=\"stat reveal\"><b>24/7</b><span>autonomous syncing</span></div>\n    <div class=\"stat reveal\"><b>0</b><span>tribal knowledge lost</span></div>\n  </div>\n</div>\n\n<!-- QUOTE -->\n<section class=\"quote\">\n  <div class=\"wrap reveal\">\n    <div class=\"qmark\">\"</div>\n    <blockquote>The team's knowledge used to live in people's heads and a thousand Slack threads. Now it lives in <span class=\"gold\">one brain that cites its work</span> — and it keeps itself current while we sleep.</blockquote>\n    <div class=\"qattr\">— Built and proven in production by the engineering team at Endurance AI Labs</div>\n  </div>\n</section>\n\n<!-- FAQ -->\n<section class=\"faq\" id=\"faq\">\n  <div class=\"wrap\">\n    <div class=\"sec-head center reveal\">\n      <span class=\"eyebrow\"><span class=\"dot\">●</span> FAQ</span>\n      <h2>Questions, answered.</h2>\n    </div>\n    <div class=\"faq-list reveal\">\n      <div class=\"qa\">\n        <button>How is this different from a search tool or a wiki?<span class=\"pm\">+</span></button>\n        <div class=\"ans\"><p>A wiki goes stale the moment you stop editing it; a search tool just finds documents. Endurance Brain <em>writes and maintains the wiki for you</em> — continuously synthesizing your raw sources into structured, cited pages, and linting itself for contradictions and staleness. You get the readability of a wiki with the freshness of a live feed.</p></div>\n      </div>\n      <div class=\"qa\">\n        <button>How does it avoid making things up?<span class=\"pm\">+</span></button>\n        <div class=\"ans\"><p>The schema enforces a hard citation rule: no synthesized claim is allowed without a link to a real underlying source. When evidence is thin, the brain states that explicitly instead of guessing. A deterministic lint pass continuously flags any unbacked claim. Trust isn't a setting — it's built into how the system is constructed.</p></div>\n      </div>\n      <div class=\"qa\">\n        <button>Where does our data live?<span class=\"pm\">+</span></button>\n        <div class=\"ans\"><p>Entirely in your environment. Endurance Brain self-hosts on your cloud or on-prem infrastructure. Raw source material — emails, documents, messages — never leaves your perimeter, and connectors authenticate with your own read-only credentials.</p></div>\n      </div>\n      <div class=\"qa\">\n        <button>Which tools can it connect to?<span class=\"pm\">+</span></button>\n        <div class=\"ans\"><p>Out of the box: email/Outlook, Slack &amp; Teams, Google Drive, SharePoint &amp; OneDrive, Box, Dropbox, Notion, Confluence, Jira, Asana, Linear, Monday, ServiceNow, Zendesk, Zoom/Meet/Teams transcripts, Gong, Fireflies, Salesforce, HubSpot, NetSuite, deal rooms (Datasite, Intralinks), industry DMS (iManage, NetDocuments), and code repositories (GitHub, GitLab, Bitbucket). The connector layer is modular — if a system has an API, it can be added.</p></div>\n      </div>\n      <div class=\"qa\">\n        <button>How much upkeep does it require?<span class=\"pm\">+</span></button>\n        <div class=\"ans\"><p>Effectively none. Scheduled syncs ingest new activity and re-compile the wiki automatically around the clock. A human operator can steer high-level synthesis and review lint findings, but the brain stays current on its own.</p></div>\n      </div>\n      <div class=\"qa\">\n        <button>How long until it's useful?<span class=\"pm\">+</span></button>\n        <div class=\"ans\"><p>The first full ingest builds a usable brain from your existing history immediately — then it only compounds. New hires can start asking questions on day one instead of waiting months to absorb tribal knowledge.</p></div>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- CTA -->\n<section class=\"cta\" id=\"cta\">\n  <div class=\"glow\"></div>\n  <div class=\"cta-in\">\n    <div class=\"wrap\">\n      <span class=\"eyebrow reveal\"><span class=\"dot\">●</span> Get started</span>\n      <h2 class=\"reveal\">Give your firm a memory<span class=\"gold\">that never forgets.</span></h2>\n      <p class=\"reveal\">Deploy Endurance Brain on your infrastructure and turn a decade of scattered context into one cited, self-maintaining source of truth.</p>\n      <div class=\"cta-row reveal\">\n        <a href=\"#\" data-demo class=\"btn btn-gold\">Book a demo &nbsp;→</a>\n        <a href=\"#how\" class=\"btn btn-ghost\">See how it works</a>\n      </div>\n      <p class=\"fine reveal\">Private deployment · Your data stays yours · Built by Endurance AI Labs</p>\n    </div>\n  </div>\n</section>\n\n<!-- FOOTER -->\n<footer>\n  <div class=\"wrap\">\n    <div class=\"foot-grid\">\n      <div class=\"foot-brand\">\n        <a href=\"#top\" class=\"brand\" aria-label=\"Endurance AI Labs — Brain\">\n          <img src=\"/logo-endurance.svg\" alt=\"Endurance AI Labs\" class=\"wordmark\" />\n          <span class=\"bdiv\"></span>\n          <span class=\"bprod\">Brain</span>\n        </a>\n        <p>Autonomous institutional memory for knowledge-heavy firms. Every source, unified. Every claim, cited.</p>\n      </div>\n      <div class=\"foot-col\">\n        <h4>Product</h4>\n        <a href=\"#how\">How it works</a>\n        <a href=\"#features\">Capabilities</a>\n        <a href=\"#versus\">Why it's different</a>\n        <a href=\"#security\">Security</a>\n        <a href=\"/brain/reel\">▶ Watch the reel</a>\n        <a href=\"/brain/console\">Open the console</a>\n      </div>\n      <div class=\"foot-col\">\n        <h4>Industries</h4>\n        <a href=\"#industries\">Law Firms</a>\n        <a href=\"#industries\">Real Estate</a>\n        <a href=\"#industries\">Logistics</a>\n        <a href=\"#industries\">VC &amp; Private Equity</a>\n      </div>\n      <div class=\"foot-col\">\n        <h4>Company</h4>\n        <a href=\"#\" data-demo>Book a demo</a>\n        <a href=\"#\" data-demo>Contact</a>\n        <a href=\"#faq\">FAQ</a>\n      </div>\n    </div>\n    <div class=\"foot-bot\">\n      <p>© 2026 Endurance AI Labs. All rights reserved.</p>\n      <p class=\"coords\">68°44′21″S <span class=\"dot\">·</span> 52°19′47″W — Endurance</p>\n    </div>\n  </div>\n</footer>\n\n<!-- SVG ICON SPRITE -->\n<svg width=\"0\" height=\"0\" style=\"position:absolute\" aria-hidden=\"true\">\n  <defs>\n    <g id=\"i-link\"><path d=\"M10 13a5 5 0 0 0 7 0l3-3a5 5 0 0 0-7-7l-1 1\"/><path d=\"M14 11a5 5 0 0 0-7 0l-3 3a5 5 0 0 0 7 7l1-1\"/></g>\n    <g id=\"i-person\"><circle cx=\"12\" cy=\"8\" r=\"4\"/><path d=\"M4 21a8 8 0 0 1 16 0\"/></g>\n    <g id=\"i-layers\"><path d=\"m12 2 9 5-9 5-9-5 9-5Z\"/><path d=\"m3 12 9 5 9-5\"/><path d=\"m3 17 9 5 9-5\"/></g>\n    <g id=\"i-refresh\"><path d=\"M21 12a9 9 0 1 1-3-6.7\"/><path d=\"M21 4v5h-5\"/></g>\n    <g id=\"i-shield\"><path d=\"M12 2 4 5v6c0 5 3.5 8.5 8 11 4.5-2.5 8-6 8-11V5l-8-3Z\"/><path d=\"m9 12 2 2 4-4\"/></g>\n    <g id=\"i-scale\"><path d=\"M12 3v18M5 21h14M7 7l-3 7h6l-3-7Zm10 0-3 7h6l-3-7ZM5 7h14\"/></g>\n    <g id=\"i-chat\"><path d=\"M21 15a2 2 0 0 1-2 2H8l-5 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2Z\"/></g>\n    <g id=\"i-clock\"><circle cx=\"12\" cy=\"12\" r=\"9\"/><path d=\"M12 7v5l3 2\"/></g>\n    <g id=\"i-history\"><path d=\"M3 12a9 9 0 1 0 3-6.7L3 8\"/><path d=\"M3 3v5h5\"/><path d=\"M12 7v5l3 2\"/></g>\n    <g id=\"i-plug\"><path d=\"M9 2v6M15 2v6M6 8h12v3a6 6 0 0 1-12 0Z\"/><path d=\"M12 17v5\"/></g>\n    <g id=\"i-check\"><path d=\"M20 6 9 17l-5-5\"/></g>\n    <g id=\"i-x\"><path d=\"M18 6 6 18M6 6l12 12\"/></g>\n    <g id=\"i-building\"><path d=\"M4 21V5a2 2 0 0 1 2-2h7a2 2 0 0 1 2 2v16\"/><path d=\"M15 9h3a2 2 0 0 1 2 2v10\"/><path d=\"M8 7h2M8 11h2M8 15h2\"/></g>\n    <g id=\"i-truck\"><path d=\"M1 6h13v9H1zM14 9h4l3 3v3h-7z\"/><circle cx=\"6\" cy=\"18\" r=\"2\"/><circle cx=\"18\" cy=\"18\" r=\"2\"/></g>\n    <g id=\"i-rocket\"><path d=\"M5 13c-1.5.5-3 2-3 6 4 0 5.5-1.5 6-3\"/><path d=\"M14 4c4 0 6 2 6 6 0 5-4 8-10 12C6 18 4 14 4 10c4-6 7-6 10-6Z\"/><circle cx=\"13\" cy=\"9\" r=\"1.5\"/></g>\n    <g id=\"i-chart\"><path d=\"M3 3v18h18\"/><path d=\"m7 14 3-4 3 3 4-6\"/></g>\n    <g id=\"i-bank\"><path d=\"M3 10 12 4l9 6M4 10h16M5 10v8M19 10v8M9 10v8M15 10v8M3 21h18\"/></g>\n    <g id=\"i-briefcase\"><rect x=\"3\" y=\"7\" width=\"18\" height=\"13\" rx=\"2\"/><path d=\"M8 7V5a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2M3 13h18\"/></g>\n    <g id=\"i-heart\"><path d=\"M19 5a5 5 0 0 0-7 0l0 0-0 0a5 5 0 0 0-7 7l7 7 7-7a5 5 0 0 0 0-7Z\"/></g>\n    <g id=\"i-cpu\"><rect x=\"6\" y=\"6\" width=\"12\" height=\"12\" rx=\"2\"/><path d=\"M9 1v3M15 1v3M9 20v3M15 20v3M1 9h3M1 15h3M20 9h3M20 15h3\"/></g>\n    <g id=\"i-server\"><rect x=\"3\" y=\"4\" width=\"18\" height=\"7\" rx=\"2\"/><rect x=\"3\" y=\"13\" width=\"18\" height=\"7\" rx=\"2\"/><path d=\"M7 7.5h.01M7 16.5h.01\"/></g>\n    <g id=\"i-lock\"><rect x=\"4\" y=\"11\" width=\"16\" height=\"10\" rx=\"2\"/><path d=\"M8 11V7a4 4 0 0 1 8 0v4\"/></g>\n    <g id=\"i-key\"><circle cx=\"8\" cy=\"8\" r=\"5\"/><path d=\"m11.5 11.5 8 8M16 16l2-2M19 19l2-2\"/></g>\n    <g id=\"i-git\"><circle cx=\"6\" cy=\"6\" r=\"2.5\"/><circle cx=\"6\" cy=\"18\" r=\"2.5\"/><circle cx=\"18\" cy=\"9\" r=\"2.5\"/><path d=\"M6 8.5v7M18 11.5c0 3-4 3.5-7 3.5\"/></g>\n    <g id=\"i-handshake\"><path d=\"m11 17 2 2a1.5 1.5 0 0 0 2-2\"/><path d=\"m13 17 2.5 2.5a1.5 1.5 0 0 0 2-2L13 13\"/><path d=\"M3 9 8 4l4 3 5-2 4 4\"/><path d=\"m3 9 4 4 3-2\"/><path d=\"m21 9-4 4\"/></g>\n    <g id=\"i-calculator\"><rect x=\"5\" y=\"2\" width=\"14\" height=\"20\" rx=\"2\"/><path d=\"M8 6h8M8 10h.01M12 10h.01M16 10h.01M8 14h.01M12 14h.01M16 14h4M8 18h.01M12 18h.01\"/></g>\n    <g id=\"i-umbrella\"><path d=\"M12 2a9 9 0 0 1 9 9H3a9 9 0 0 1 9-9Z\"/><path d=\"M12 11v8a2.5 2.5 0 0 1-5 0\"/></g>\n    <g id=\"i-gem\"><path d=\"M6 3h12l4 6-10 12L2 9Z\"/><path d=\"M2 9h20M9 3 6 9l6 12 6-12-3-6\"/></g>\n    <g id=\"i-ruler\"><path d=\"M3 17 17 3l4 4L7 21Z\"/><path d=\"M14 6l1.5 1.5M11 9l1.5 1.5M8 12l1.5 1.5M5 15l1.5 1.5\"/></g>\n    <g id=\"i-cloud\"><path d=\"M17.5 19a4.5 4.5 0 0 0 0-9 6 6 0 0 0-11.6-1.5A4 4 0 0 0 6 19Z\"/></g>\n    <g id=\"i-landmark\"><path d=\"M3 21h18M4 10h16M5 10 12 4l7 6M6 10v8M10 10v8M14 10v8M18 10v8\"/></g>\n    <g id=\"i-bolt\"><path d=\"M13 2 4 14h7l-1 8 9-12h-7Z\"/></g>\n    <g id=\"i-megaphone\"><path d=\"m3 11 15-6v14L3 13Z\"/><path d=\"M3 11v2a3 3 0 0 0 3 3h1M11 9v8\"/></g>\n    <g id=\"i-users\"><circle cx=\"9\" cy=\"8\" r=\"3.5\"/><path d=\"M2.5 20a6.5 6.5 0 0 1 13 0\"/><path d=\"M16 5a3.5 3.5 0 0 1 0 6.5M17 14.5a6.5 6.5 0 0 1 4.5 5.5\"/></g>\n    <g id=\"i-award\"><circle cx=\"12\" cy=\"9\" r=\"6\"/><path d=\"m8.5 14-1.5 7 5-3 5 3-1.5-7\"/></g>\n    <g id=\"i-eyeoff\"><path d=\"M9.9 5.1A9.5 9.5 0 0 1 12 5c6 0 10 7 10 7a17 17 0 0 1-3 3.6M6.3 6.3A17 17 0 0 0 2 12s4 7 10 7a9.5 9.5 0 0 0 4-.9\"/><path d=\"M9.5 9.5a3.5 3.5 0 0 0 5 5M3 3l18 18\"/></g>\n    <g id=\"i-radar\"><path d=\"M12 12 8 6\"/><path d=\"M21 12a9 9 0 1 1-5-8\"/><path d=\"M16 4a9 9 0 0 0-4 8\"/><circle cx=\"12\" cy=\"12\" r=\"2\"/></g>\n  </defs>\n</svg>\n\n<script>\n/* ---------- NAV scroll state ---------- */\nconst nav=document.getElementById('nav');\naddEventListener('scroll',()=>nav.classList.toggle('scrolled',scrollY>20));\n\n/* ---------- Reveal on scroll ---------- */\nconst io=new IntersectionObserver((es)=>{\n  es.forEach(e=>{if(e.isIntersecting){e.target.classList.add('in');io.unobserve(e.target);}});\n},{threshold:.12});\ndocument.querySelectorAll('.reveal').forEach((el,i)=>{el.style.transitionDelay=(i%3*60)+'ms';io.observe(el);});\n\n/* ---------- FAQ accordion ---------- */\ndocument.querySelectorAll('.qa button').forEach(b=>{\n  b.addEventListener('click',()=>{\n    const qa=b.parentElement, ans=qa.querySelector('.ans'), open=qa.classList.contains('open');\n    document.querySelectorAll('.qa').forEach(x=>{x.classList.remove('open');x.querySelector('.ans').style.maxHeight=null;});\n    if(!open){qa.classList.add('open');ans.style.maxHeight=ans.scrollHeight+'px';}\n  });\n});\n\n/* ---------- \"Book a demo\" mailto (assembled at runtime so it survives\n   Cloudflare email obfuscation and keeps addresses away from scrapers) ---------- */\n(function(){\n  var dom='endurancelabs'+'.'+'ai';\n  var cc=['ramzy','alex','nick'].map(function(u){return u+'@'+dom;}).join(',');\n  var subject=encodeURIComponent('Endurance Brain Demo Request');\n  var body=encodeURIComponent(\n    \"Hi Endurance team,\\n\\nI'd like to book a demo of Endurance Brain.\\n\\nName:\\nCompany:\\nRole:\\nUse case:\\n\\nThanks\"\n  );\n  var href='mailto:?cc='+cc+'&subject='+subject+'&body='+body;\n  document.querySelectorAll('a[data-demo]').forEach(function(a){\n    a.addEventListener('click',function(e){\n      e.preventDefault();\n      window.location.href=href;\n    });\n  });\n})();\n\n/* ---------- Hero network canvas (glowing dot map) ---------- */\n(function(){\n  const c=document.getElementById('net'), x=c.getContext('2d');\n  let w,h,dpr,nodes=[],raf;\n  const GOLD='46,111,242';\n  function size(){\n    dpr=Math.min(devicePixelRatio||1,2);\n    w=c.clientWidth;h=c.clientHeight;\n    c.width=w*dpr;c.height=h*dpr;x.setTransform(dpr,0,0,dpr,0,0);\n    build();\n  }\n  function build(){\n    const density=Math.max(28,Math.min(74,Math.floor(w*h/17000)));\n    nodes=[];\n    for(let i=0;i<density;i++){\n      nodes.push({\n        x:Math.random()*w, y:Math.random()*h,\n        vx:(Math.random()-.5)*.26, vy:(Math.random()-.5)*.26,\n        r:Math.random()*2.8+1.6,\n        p:Math.random()*Math.PI*2\n      });\n    }\n  }\n  function frame(){\n    x.clearRect(0,0,w,h);\n    const R=185;\n    // links\n    for(let i=0;i<nodes.length;i++){\n      const a=nodes[i];\n      for(let j=i+1;j<nodes.length;j++){\n        const b=nodes[j], dx=a.x-b.x, dy=a.y-b.y, d=Math.hypot(dx,dy);\n        if(d<R){\n          const o=(1-d/R)*.30;\n          x.strokeStyle='rgba('+GOLD+','+o+')';\n          x.lineWidth=1;\n          x.beginPath();x.moveTo(a.x,a.y);x.lineTo(b.x,b.y);x.stroke();\n        }\n      }\n    }\n    // nodes\n    for(const n of nodes){\n      n.x+=n.vx;n.y+=n.vy;n.p+=.022;\n      if(n.x<0||n.x>w)n.vx*=-1;\n      if(n.y<0||n.y>h)n.vy*=-1;\n      const tw=(Math.sin(n.p)*.4+.6);\n      // soft outer halo\n      x.beginPath();\n      x.fillStyle='rgba('+GOLD+','+(.10*tw)+')';\n      x.arc(n.x,n.y,n.r*3.4,0,Math.PI*2);x.fill();\n      // bright core with glow\n      x.beginPath();\n      x.fillStyle='rgba('+GOLD+','+(.7*tw+.3)+')';\n      x.shadowBlur=18;x.shadowColor='rgba('+GOLD+',.85)';\n      x.arc(n.x,n.y,n.r,0,Math.PI*2);x.fill();\n      x.shadowBlur=0;\n    }\n    raf=requestAnimationFrame(frame);\n  }\n  size();frame();\n  addEventListener('resize',()=>{cancelAnimationFrame(raf);size();frame();});\n})();\n</script>\n</body>\n</html>\n";

export async function GET() {
  return new Response(HTML, {
    headers: { "content-type": "text/html; charset=utf-8" },
  });
}
